        function toggleMenu() {
            var nav = document.getElementById('nav-links');
            if (window.innerWidth <= 768) {
                nav.classList.toggle('active');
            }
        }

        function gotoPage(id) {
            document.querySelectorAll('.page,.dash-wrap').forEach(p => {
                p.classList.remove('show');
                p.style.display = 'none';
            });
            var el = document.getElementById(id);
            el.classList.add('show');
            // Auth pages need flex
            if (['pg-login', 'pg-register'].includes(id)) el.style.display = 'flex';
            else el.style.display = '';
            window.scrollTo(0, 0);
        }

        function showSec(sec) {
            document.querySelectorAll('.home-sec').forEach(s => s.classList.remove('show'));
            document.getElementById('sec-' + sec).classList.add('show');
            if (sec === 'catalogue') renderPubCat();
            window.scrollTo(0, 70);
        }

        function setAct(el) {
            document.querySelectorAll('.nav-link').forEach(a => a.classList.remove('active'));
            el.classList.add('active');
        }

        setRole('student');
        loadDB().then(() => renderPubCat());
        // Set hero image
        document.getElementById('hero-img').style.backgroundImage = "url('data:image/png;base64,')";
    